import { useState } from 'react';
import { sendContactForm } from '../utils/web3forms';

const ContactForm = () => {
  const [form, setForm] = useState({ name:'', email:'', message:'' });
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // ✅ Validation simple
  const validateForm = () => {
    if (!form.name.trim()) return "Name is required";
    if (!form.email.trim()) return "Email is required";

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(form.email)) return "Invalid email format";

    if (!form.message.trim()) return "Message is required";
    if (form.message.length < 10) return "Message must be at least 10 characters";

    return null;
  };

  const handleChange = (e) => {
    setForm(f => ({ ...f, [e.target.name]: e.target.value }));
  };

  // ✅ Envoi réel API
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);

    const validationError = validateForm();
    if (validationError) {
      setError(validationError);
      return;
    }

    setLoading(true);

    try {
      await sendContactForm(form);

      setSubmitted(true);
      setForm({ name:'', email:'', message:'' });

      setTimeout(() => {
        setSubmitted(false);
      }, 4000);

    } catch (err) {
      console.error(err);
      setError("Failed to send message. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = {
    width:'100%',
    padding:'12px 16px',
    border:'1px solid #e5e7eb',
    borderRadius:8,
    fontFamily:'DM Sans,sans-serif',
    fontSize:'0.92rem',
    color:'#1a1a2e',
    background:'#f9fafb',
    outline:'none',
    transition:'border-color 0.2s,box-shadow 0.2s',
    boxSizing:'border-box'
  };

  const labelStyle = {
    display:'block',
    fontFamily:'Syne,sans-serif',
    fontWeight:600,
    fontSize:'0.8rem',
    letterSpacing:'0.5px',
    color:'#3f444a',
    textTransform:'uppercase',
    marginBottom:'0.4rem'
  };

  const focusIn = (e) => {
    e.target.style.borderColor='#ec4848';
    e.target.style.boxShadow='0 0 0 3px rgba(236,72,72,0.12)';
    e.target.style.background='#fff';
  };

  const focusOut = (e) => {
    e.target.style.borderColor='#e5e7eb';
    e.target.style.boxShadow='none';
    e.target.style.background='#f9fafb';
  };

  return (
    <section id="contact" style={{ padding:'80px 0', background:'#1a1a2e' }}>
      <div className="container">

        {/* HEADER */}
        <div className="reveal" style={{ textAlign:'center', marginBottom:'3rem' }}>
          <span style={{ display:'inline-block', background:'rgba(236,72,72,0.15)', color:'#ff8c69', fontFamily:'Syne,sans-serif', fontWeight:700, fontSize:'0.72rem', letterSpacing:'2px', textTransform:'uppercase', padding:'5px 14px', borderRadius:20, border:'1px solid rgba(236,72,72,0.3)', marginBottom:'0.9rem' }}>Contact</span>
          <h2 style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:'clamp(1.6rem,4vw,2.2rem)', color:'#fff', marginBottom:'0.6rem' }}>Let's Talk Fashion AI</h2>
          <p style={{ fontFamily:'DM Sans,sans-serif', fontSize:'1rem', color:'rgba(255,255,255,0.6)', maxWidth:480, margin:'0 auto' }}>
            Have a question or a custom requirement? Our team will get back to you quickly.
          </p>
        </div>

        <div className="reveal" style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(280px,1fr))', gap:'3rem', alignItems:'start', maxWidth:900, margin:'0 auto' }}>

          {/* FORM */}
          <div style={{ background:'#fff', borderRadius:16, padding:'2rem', boxShadow:'0 20px 60px rgba(0,0,0,0.25)' }}>

            {submitted ? (
              <div style={{ textAlign:'center', padding:'2.5rem 1rem' }}>
                <h3 style={{ fontFamily:'Syne,sans-serif', fontWeight:800 }}>Message Sent!</h3>
                <p>We'll get back to you as soon as possible.</p>
              </div>
            ) : (
              <form onSubmit={handleSubmit}>

                {/* ERROR */}
                {error && (
                  <p style={{ color:'red', marginBottom:'1rem', fontSize:'0.9rem' }}>
                    {error}
                  </p>
                )}

                <div style={{ marginBottom:'1.2rem' }}>
                  <label style={labelStyle}>Name</label>
                  <input name="name" value={form.name} onChange={handleChange} style={inputStyle} onFocus={focusIn} onBlur={focusOut} />
                </div>

                <div style={{ marginBottom:'1.2rem' }}>
                  <label style={labelStyle}>Email</label>
                  <input name="email" value={form.email} onChange={handleChange} style={inputStyle} onFocus={focusIn} onBlur={focusOut} />
                </div>

                <div style={{ marginBottom:'1.5rem' }}>
                  <label style={labelStyle}>Message</label>
                  <textarea name="message" value={form.message} onChange={handleChange} rows={5} style={{ ...inputStyle }} onFocus={focusIn} onBlur={focusOut} />
                </div>

                <button type="submit" disabled={loading} style={{ width:'100%', background: loading ? '#aaa' : '#ec4848', color:'#fff', padding:'13px', borderRadius:8 }}>
                  {loading ? "Sending..." : "Send Message"}
                </button>

              </form>
            )}

          </div>
        </div>
      </div>
    </section>
  );
};

export default ContactForm;
